<template>
    <div>
        <div class="header">
            <h1>Will's Books</h1>
            <button class="add-btn" @click="showAddModal = true">+ Add Book</button>
        </div>
        <BookTable :books="books" @book-updated="onBookUpdated" @book-deleted="onBookDeleted"/>
        <AddBookModal v-if="showAddModal" @close="showAddModal = false" @book-added="onBookAdded"/>
    </div>
</template>



<script>
import BookTable from '../components/BookTable.vue';
import AddBookModal from '../components/modals/AddBookModal.vue'
import { supabase } from '../supabase'

export default {
    name: 'WillsBooksView',
    data() {
        return {
            books: [],
            showAddModal: false
        }
    },
    async mounted() {
        const { data, error } = await supabase
            .from('WillBooks')
            .select('*')
        if (error) {
            console.error('Error fetching books:', error)
        } else {
            this.books = data
        }
    },
    components: {
        BookTable,
        AddBookModal
    },
    methods: {
        onBookAdded(book) {
            this.books.push(book)
        },
        onBookUpdated(updatedBook) {
            const i = this.books.findIndex(b => b.id === updatedBook.id)
            if (i !== -1) this.books.splice(i, 1, updatedBook)
        },
        onBookDeleted(id) {
            this.books = this.books.filter(b => b.id !== id)
        }
    }
}
</script>
