<template>
    <div class="overlay" @click="confirmClose">
        <div class="modal" @click.stop>
            <button class="close-btn" @click="confirmClose">✕</button>
            <h2>Edit Book</h2>
            <div class="form-group">
                <label>Title</label>
                <input v-model="form.Title"/>
            </div>
            <div class="form-group">
                <label>Author</label>
                <input v-model="form.Author"/>
            </div>
            <div class="form-group">
                <label>Year Read</label>
                <input v-model="form.YearRead"/>
            </div>
            <div class="form-group">
                <label>Rating</label>
                <input v-model="form.Rating" placeholder="/10"/>
            </div>
            <div class="form-group thoughts-group">
                <textarea v-model="form.Thoughts" placeholder="Thoughts" />
            </div>
            <button class="add-btn" @click="submit">Save Changes</button>
        </div>
    </div>
</template>


<script>
import { supabase } from '../../supabase'

export default {
    name: 'EditBookModal',
    props: {
        book: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            form: { ...this.book }
        }
    },
    computed: {
        hasChanges() {
            return Object.keys(this.form).some(k => this.form[k] !== this.book[k])
        }
    },
    mounted() {
        window.addEventListener('keydown', this.handleKeyDown)
    },
    beforeUnmount() {
        window.removeEventListener('keydown', this.handleKeyDown)
    },
    methods: {
        handleKeyDown(e) {
            if (e.key === 'Escape') this.confirmClose()
        },
        confirmClose() {
            if (this.hasChanges) {
                if (confirm('You have unsaved changes. Are you sure you want to close?')) {
                    this.$emit('close')
                }
            } else {
                this.$emit('close')
            }
        },
        async submit() {
            const allBlank = Object.values(this.form).every(v => v === '' || v === null)
            
            if (allBlank) {
                const { error } = await supabase
                    .from('WillBooks')
                    .delete()
                    .eq('id', this.book.id)
                if (error) {
                    console.error('Error deleting book:', error)
                } else {
                    this.$emit('book-deleted', this.book.id)
                    this.$emit('close')
                }
            } else {
                const { error } = await supabase
                    .from('WillBooks')
                    .update(this.form)
                    .eq('id', this.book.id)
                if (error) {
                    console.error('Error updating book:', error)
                } else {
                    this.$emit('book-updated', this.form)
                    this.$emit('close')
                }
            }
        }
    }
}
</script>