<template>
    <div class="overlay" @click="confirmClose">
        <div class="modal" @click.stop>
            <button class="close-btn" @click="confirmClose">✕</button>
            <h2>Add Book</h2>
            <div class="form-group">
                <label>Title</label>
                <input v-model="form.Title"/>
            </div>
            <div class="form-group">
                <label>Author</label>
                <input v-model="form.Author"/>
            </div>
            <div class="form-group">
                <label>Year Read</label>
                <input v-model="form.YearRead"/>
            </div>
            <div class="form-group">
                <label>Rating</label>
                <input v-model="form.Rating" placeholder="/10"/>
            </div>
            <div class="form-group">
                <textarea v-model="form.Thoughts" placeholder="Thoughts" />
            </div>
            <button class="add-btn" @click="submit">Add Book</button>
        </div>
    </div>
</template>

<script>
import { supabase } from '../../supabase'

export default {
    name: 'AddBookModal',
    data() {
        return {
            form: { Title: '', Author: '', YearRead: '', Rating: '', Thoughts: '' }
        }
    },

    computed: {
        hasChanges() {
            return Object.values(this.form).some(v => v !== '')
        }
    },

    mounted() {
        window.addEventListener('keydown', this.handleKeyDown)
    },
    beforeUnmount() {
        window.removeEventListener('keydown', this.handleKeyDown)
    },
    methods: {
        handleKeyDown(e) {
            if (e.key === 'Escape') this.confirmClose()
        },
        async submit() {
            const { data, error } = await supabase
                .from('WillBooks')
                .insert([this.form])
                .select()
            if (error) {
                console.error('Error adding book:', error)
            } else {
                this.$emit('book-added', data[0])
                this.$emit('close')
            }
        },

        confirmClose() {
            if (this.hasChanges) {
                if (confirm('You have unsaved changes. Are you sure you want to close?')) {
                    this.$emit('close')
                }
            } else {
                this.$emit('close')
            }
        }
    }
}

</script>